#include<bits/stdc++.h>
using namespace std;
const int MAXN = 5e7 + 10;
int pre[MAXN], a[MAXN], maxi = -MAXN * 5000;
deque<int>q;
int main(){
	int n,m;
	cin >> n >> m;
	for(int i = 1; i <= n ; i++){
		cin >> a[i];
		pre[i] = pre[i - 1] + a[i];
	}
	for(int i = 1; i <= n; i++){
		while(!q.empty() && q.front() + m < i) q.pop_front();
        maxi = max(maxi, pre[i] - pre[q.front()]);
        while(!q.empty() && pre[i] <= pre[q.back()])q.pop_back();
        q.push_back(i); 
	}
	cout << maxi;
}
